const now = new Date();
const dayOfWeek = now.getDay();
const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + mondayOffset);
monday.setHours(0, 0, 0, 0);
const nextFriday = new Date(monday);
nextFriday.setDate(monday.getDate() + 11);
nextFriday.setHours(23, 59, 59, 999);

const todayStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const workStart = $.input.workHoursStart || 9;
const workEnd = $.input.workHoursEnd || 17;

return { timeMin: monday.toISOString(), timeMax: nextFriday.toISOString(), today: todayStr, workStart, workEnd };

const response = $.steps.listEvents.response;
const events = response.items || response.data || [];
let compiled = '';
let eventCount = 0;
let totalMeetingMinutes = 0;
const dayMap = {};

if (Array.isArray(events)) {
  events.forEach((e, i) => {
    const startStr = e.start ? (e.start.dateTime || e.start.date || '') : '';
    const endStr = e.end ? (e.end.dateTime || e.end.date || '') : '';
    const day = startStr.split('T')[0] || 'unknown';
    if (!dayMap[day]) dayMap[day] = [];
    dayMap[day].push(e.summary || '(no title)');

    compiled += 'EVENT ' + (i + 1) + ': ' + (e.summary || '(no title)') + '\n';
    compiled += '  Start: ' + startStr + ' | End: ' + endStr + '\n';
    if (e.location) compiled += '  Location: ' + e.location + '\n';
    const attendees = (e.attendees || []).map(a => (a.displayName || a.email)).join(', ');
    if (attendees) compiled += '  Attendees: ' + attendees + '\n';
    if (e.description) compiled += '  Notes: ' + (e.description || '').slice(0, 150) + '\n';
    compiled += '\n';
    eventCount++;

    if (startStr.includes('T') && endStr.includes('T')) {
      const diff = (new Date(endStr) - new Date(startStr)) / 60000;
      if (diff > 0 && diff < 480) totalMeetingMinutes += diff;
    }
  });
}

const dailySummary = Object.entries(dayMap).map(([day, evts]) => day + ': ' + evts.length + ' events').join(', ');

return { compiled, eventCount, totalMeetingMinutes, dailySummary };

const d = $.steps.compileSchedule.output;
const dr = $.steps.getDateRange.output;
const focus = $.input.optimizationFocus || '';

let prompt = 'You are a productivity coach and schedule optimization expert. Analyze the following calendar schedule and provide detailed optimization recommendations.\n\n';
prompt += 'CURRENT DATE: ' + dr.today + '\n';
prompt += 'WORK HOURS: ' + dr.workStart + ':00 to ' + dr.workEnd + ':00\n';
prompt += 'TOTAL EVENTS: ' + d.eventCount + '\n';
prompt += 'TOTAL MEETING TIME: ' + Math.round(d.totalMeetingMinutes / 60) + ' hours\n';
prompt += 'DAILY BREAKDOWN: ' + d.dailySummary + '\n\n';

if (focus) {
  prompt += 'OPTIMIZATION FOCUS: ' + focus + '\n\n';
}

prompt += 'CALENDAR EVENTS:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify schedule inefficiencies (too many meetings, no focus time, poor time-blocking)\n';
prompt += '- Suggest specific optimizations with before/after comparisons\n';
prompt += '- Recommend meetings to cancel, shorten, or combine\n';
prompt += '- Identify ideal focus time blocks for deep work\n';
prompt += '- Flag back-to-back meetings without breaks\n';
prompt += '- Score the overall schedule health (1-10)\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "scheduleHealthScore": 7,\n';
prompt += '  "weekSummary": "overview of the week",\n';
prompt += '  "topIssues": ["issue 1", "issue 2"],\n';
prompt += '  "optimizations": [\n';
prompt += '    { "type": "cancel|shorten|move|combine", "event": "meeting name", "suggestion": "what to do", "timeSaved": "30 min", "impact": "high|medium|low" }\n';
prompt += '  ],\n';
prompt += '  "focusTimeBlocks": [{ "day": "Monday", "time": "9:00-11:00", "bestFor": "type of work" }],\n';
prompt += '  "backToBackWarnings": [{ "meetings": ["meeting1", "meeting2"], "gap": "0 min", "suggestion": "add break" }],\n';
prompt += '  "meetingLoadByDay": [{ "day": "Monday", "hours": 4, "assessment": "too heavy" }],\n';
prompt += '  "overallRecommendation": "top priority action to improve schedule"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { scheduleHealthScore: 5, weekSummary: raw, topIssues: [], optimizations: [], focusTimeBlocks: [], backToBackWarnings: [], meetingLoadByDay: [], overallRecommendation: '' }; }

const ai = $.steps.parseAI.output;
const dr = $.steps.getDateRange.output;
const d = $.steps.compileSchedule.output;

const score = ai.scheduleHealthScore || 5;
const scoreEmoji = score >= 8 ? ':white_check_mark:' : score >= 5 ? ':large_yellow_circle:' : ':red_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Schedule Optimization Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Date:*\n' + dr.today },
  { type: 'mrkdwn', text: scoreEmoji + ' *Health Score:*\n' + score + '/10' }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Events:*\n' + d.eventCount },
  { type: 'mrkdwn', text: '*Meeting Hours:*\n' + Math.round(d.totalMeetingMinutes / 60) + 'h' }
] });
blocks.push({ type: 'divider' });

const summary = (ai.weekSummary || 'No analysis available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Week Overview:*\n' + summary } });

if (ai.overallRecommendation) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':bulb: *Top Recommendation:* ' + ai.overallRecommendation } });
}

if (ai.topIssues && ai.topIssues.length > 0) {
  blocks.push({ type: 'divider' });
  let issueText = '*Top Issues:*\n';
  ai.topIssues.slice(0, 5).forEach((iss, i) => { issueText += (i + 1) + '. ' + iss + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: issueText.slice(0, 1800) } });
}

if (ai.optimizations && ai.optimizations.length > 0) {
  blocks.push({ type: 'divider' });
  let optText = '*Optimizations:*\n';
  ai.optimizations.slice(0, 6).forEach((o, i) => {
    const impIcon = o.impact === 'high' ? ':star:' : o.impact === 'medium' ? ':white_check_mark:' : ':ok:';
    optText += impIcon + ' *' + (o.event || 'General') + '* - ' + o.type + ': ' + o.suggestion;
    if (o.timeSaved) optText += ' (' + o.timeSaved + ' saved)';
    optText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: optText.slice(0, 1800) } });
}

if (ai.focusTimeBlocks && ai.focusTimeBlocks.length > 0) {
  blocks.push({ type: 'divider' });
  let focusText = '*Recommended Focus Blocks:*\n';
  ai.focusTimeBlocks.slice(0, 5).forEach((f, i) => {
    focusText += (i + 1) + '. ' + f.day + ' ' + f.time + ' - Best for: ' + f.bestFor + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: focusText.slice(0, 1800) } });
}

if (ai.backToBackWarnings && ai.backToBackWarnings.length > 0) {
  blocks.push({ type: 'divider' });
  let warnText = '*Back-to-Back Warnings:*\n';
  ai.backToBackWarnings.slice(0, 5).forEach((w, i) => {
    warnText += ':warning: ' + (w.meetings || []).join(' + ') + ' (' + w.gap + ' gap) - ' + w.suggestion + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: warnText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Calendar + Claude AI | One CLI' }] });

const fallbackText = 'Schedule Optimizer: Score ' + score + '/10, ' + d.eventCount + ' events, ' + (ai.optimizations || []).length + ' suggestions';
return { blocks, fallbackText };
